// field of `out` will be set accordingly.

siderust_status_t siderust_kepler_position_ex(struct siderust_orbit_t orbit,
                                              SiderustOrbitRefCenter orbit_center,
                                              double jd,
                                              struct siderust_cartesian_pos_t *out);

