siderust_status_t siderust_crossings(struct siderust_subject_t subject,
                                     struct siderust_geodetic_t observer,
                                     tempoch_period_mjd_t window,
                                     double threshold_deg,
                                     struct siderust_search_opts_t opts,
                                     struct siderust_crossing_event_t **out,
                                     uintptr_t *count);

// Culmination (local extrema) events for a subject.

siderust_status_t siderust_culminations(struct siderust_subject_t subject,
                                        struct siderust_geodetic_t observer,
                                        tempoch_period_mjd_t window,
                                        struct siderust_search_opts_t opts,
                                        struct siderust_culmination_event_t **out,
                                        uintptr_t *count);

// Periods when a body's altitude is within [min, max].
//
// Only `Body` subjects support this operation. For `Star`, `Icrs`, and
// `GenericTarget`, `SIDERUST_STATUS_T_INVALID_ARGUMENT` is returned.

siderust_status_t siderust_altitude_periods(struct siderust_subject_t subject,
                                            struct siderust_altitude_query_t query,
                                            tempoch_period_mjd_t **out,
                                            uintptr_t *count);

// Azimuth of any subject at an instant (degrees, North-clockwise).

siderust_status_t siderust_azimuth_at(struct siderust_subject_t subject,
                                      struct siderust_geodetic_t observer,
                                      double mjd,
                                      double *out_deg);

// Azimuth bearing-crossing events for a subject.

siderust_status_t siderust_azimuth_crossings(struct siderust_subject_t subject,
                                             struct siderust_geodetic_t observer,
                                             tempoch_period_mjd_t window,
                                             double bearing_deg,
                                             struct siderust_search_opts_t opts,
                                             struct siderust_azimuth_crossing_event_t **out,
                                             uintptr_t *count);

// Azimuth extrema (northernmost / southernmost bearing) for a subject.

siderust_status_t siderust_azimuth_extrema(struct siderust_subject_t subject,
                                           struct siderust_geodetic_t observer,
                                           tempoch_period_mjd_t window,
                                           struct siderust_search_opts_t opts,
                                           struct siderust_azimuth_extremum_t **out,
                                           uintptr_t *count);

// Periods when a subject's azimuth is within [min_deg, max_deg].

siderust_status_t siderust_in_azimuth_range(struct siderust_subject_t subject,
                                            struct siderust_geodetic_t observer,
                                            tempoch_period_mjd_t window,
                                            double min_deg,
                                            double max_deg,
                                            struct siderust_search_opts_t opts,
                                            tempoch_period_mjd_t **out,
                                            uintptr_t *count);

// Create a generic target from the tagged target payload.
//
// This is the canonical constructor for the compact FFI target ABI. Existing
// convenience helpers remain available as compatibility shims and forward here.

siderust_status_t siderust_generic_target_create(struct SiderustGenericTargetData data,
                                                 struct SiderustGenericTarget **out);

// Create a generic target from an ICRS spherical direction.

siderust_status_t siderust_generic_target_create_icrs(double ra_deg,
                                                      double dec_deg,
                                                      double epoch_jd,
                                                      struct SiderustGenericTarget **out);

// Create a generic target from an ICRS direction with proper motion.

siderust_status_t siderust_generic_target_create_icrs_with_pm(double ra_deg,
                                                              double dec_deg,
                                                              double epoch_jd,
                                                              double pm_ra_deg_yr,
                                                              double pm_dec_deg_yr,
                                                              siderust_ra_convention_t ra_convention,
                                                              struct SiderustGenericTarget **out);

// Free a generic target handle.
//
// # Safety
// `handle` must have been allocated by a `siderust_generic_target_create*`
// function in this crate and must not have been freed before.
 void siderust_generic_target_free(struct SiderustGenericTarget *handle);

// Get the coordinate payload from a generic target.

siderust_status_t siderust_generic_target_get_data(const struct SiderustGenericTarget *handle,
                                                   struct SiderustGenericTargetData *out);

// Get the epoch (Julian Date) of a generic target.

siderust_status_t siderust_generic_target_epoch_jd(const struct SiderustGenericTarget *handle,
                                                   double *out);

